import React, { useState } from "react";
import MainPage from "./components/MainPage";
import LoginPage from "./components/LoginPageTemp";
import RegistryPageTemp from "./components/RegistryPageTemp"; 
import axios from 'axios';
import './App.css';
import ForgotPassword from "./components/ForgotPassword";

function App() {
  const [view, setView] = useState('main'); 
  const [file, setFile] = useState(null);
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);


  const handleUpload = async () => {
    if (!file) return alert("Proszę wybrać zdjęcie!");
    setLoading(true);
    setResult("");

    const formData = new FormData();
    formData.append('file', file);

    try {

      const response = await axios.post('http://localhost:8081/api/scan', formData);
      setResult(response.data);
    } catch (error) {
      setResult("Błąd połączenia z serwerem: " + error.message);
    } finally {
      setLoading(false);
    }
  };




  if (view === 'main') {
    return (
      <MainPage 
        onLogin={() => setView('login')}
        onRegistry={() => setView('registry')} 
      />
    );
  }


  if (view === 'login') {
    return (
      <LoginPage
        onBack={() => setView('main')}
        onRegistry={() => setView('registry')} 
        onLoginSuccess={() => setView('scanner')} 
        onForgotPassword={() => setView('forgot')}
      />
    );
  }


  if (view === 'registry') {
    return (
      <RegistryPageTemp
        onBack={() => setView('main')}
        onLogin={() => setView('login')} 
      />
    );
  }
if (view === 'forgot') {
    return (
      <ForgotPassword 
        onBack={() => setView('login')} 
      />
    );
  }

  return (
  <div className="dashboard-container">

    <aside className="sidebar">
      <h2 className="sidebar-title">Historia Skanów</h2>
      <div className="history-list">

        <div className="history-item">
          <strong>2026-04-09</strong>
          <p>Wynik: Znamię łagodne</p>
        </div>
        <div className="history-item">
          <strong>2026-04-05</strong>
          <p>Wynik: Podejrzana zmiana</p>
        </div>
      </div>

      <button 
        className="back-button" 
        style={{marginTop: 'auto'}} 
        onClick={() => setView('main')}
      >
        ← WYLOGUJ
      </button>
    </aside>


    <main className="main-content">
      <h1 className="logo-top">MoleCheckerAI</h1>

      <div className="scanner-card">
        <p className="scanner-instruction">Wgraj zdjęcie do analizy AI</p>

        <div className="file-upload-wrapper">
          <input 
            type="file" 
            id="file-input" 
            onChange={(e) => setFile(e.target.files[0])} 
          />
        </div>

        <button 
          className="analyze-button" 
          onClick={handleUpload} 
          disabled={loading}
        >
          {loading ? "Analizowanie..." : "Zbadaj znamię"}
        </button>

        {result && (
          <div className="result-display">
            <h3>Wynik analizy AI:</h3>
            <p className="diagnosis-text">{result}</p>
            <p style={{fontSize: '0.8rem', color: '#aaa', marginTop: '10px'}}>
              *Pamiętaj: Wynik AI nie zastępuje wizyty u lekarza.
            </p>
          </div>
        )}
      </div>
    </main>
  </div>
);
}
export default App;
